#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn known_first_entry() {
        assert_eq!(modifier_name(1922418), "luminous_strike_buff");
    }

    #[test]
    fn known_mid_entry() {
        assert_eq!(modifier_name(2207359350), "copiedult_spawnedentity");
    }

    #[test]
    fn unknown_id_zero() {
        assert_eq!(modifier_name(0), "MODIFIER_NOT_FOUND");
    }

    #[test]
    fn unknown_id_max() {
        assert_eq!(modifier_name(u32::MAX), "MODIFIER_NOT_FOUND");
    }

    #[test]
    fn all_modifiers_not_empty() {
        assert!(!all_modifiers().is_empty());
    }
}
